PyTypeObject* DoInitWrapperSizeBox(const UClass* InClass, PyTypeObject* InSuperType, PyObject* InSuperTypes)
{
	if (InClass == nullptr)
	{
		return nullptr;
	}

	if (FUPyWrapperTypeRegistry::Get().HasWrappedClassType(InClass))
	{
		return const_cast<PyTypeObject*>(FUPyWrapperTypeRegistry::Get().GetWrappedClassType(InClass));
	}

	PyTypeObject* PyType = &UPyWrapperSizeBoxType;
	PyType->tp_flags = Py_TPFLAGS_DEFAULT | Py_TPFLAGS_BASETYPE;
	PyType->tp_base = InSuperType != nullptr ? InSuperType : &UPyWrapperObjectType;
	PyType->tp_bases = InSuperTypes;
	PyType->tp_methods = FUPyWrapperSizeBoxPyMethodDefs;
	PyType->tp_getset = FUPyWrapperSizeBoxGetSets;

	if (PyType_Ready(PyType) == 0)
	{
		FUPyWrapperTypeRegistry::Get().RegisterWrappedClassType(InClass, PyType);
		return PyType;
	}

	return nullptr;
}

void InitializeUPyWrapperSizeBox(UPyGenUtil::FNativePythonModule& ModuleInfo)
{
	FUPyWrapperTypeRegistry::Get().RegisterAutoWrappedClassCreateFunc(USizeBox::StaticClass(), DoInitWrapperSizeBox);
}

FUPyWrapperSizeBox* UPyIsSizeBox(PyObject* InSelf)
{
	if (InSelf && PyObject_IsInstance(InSelf, (PyObject*)&UPyWrapperSizeBoxType))
	{
		return (FUPyWrapperSizeBox*)InSelf;
	}
	return nullptr;
}

namespace UPyConversion
{
	FUPyConversionResult Nativize(PyObject* PyObj, USizeBox*& OutVal, const ESetErrorState SetErrorState)
	{
		if (FUPyWrapperSizeBox* PySizeBox = UPyIsSizeBox(PyObj))
		{
			if (!FUPyWrapperObject::ValidateInternalState(PySizeBox))
			{
				return FUPyConversionResult::Failure();
			}

			OutVal = PySizeBox->ValuePtr();
			return FUPyConversionResult::Success();
		}

		UPYCONVERSION_RETURN(FUPyConversionResult::Failure(), TEXT("Nativize"), *FString::Printf(TEXT("Cannot nativize '%s' as 'USizeBox'"), *UPyUtil::GetFriendlyTypename(PyObj)));
	}
}
